import{_ as t,o as h,c as i,ag as o}from"./chunks/framework.CxZWPeXl.js";const u=JSON.parse('{"title":"Quản lý Prompt","description":"","frontmatter":{},"headers":[],"relativePath":"admin-prompts.md","filePath":"admin-prompts.md"}'),a={name:"admin-prompts.md"};function r(c,n,e,l,g,p){return h(),i("div",null,[...n[0]||(n[0]=[o('<h1 id="quan-ly-prompt" tabindex="-1">Quản lý Prompt <a class="header-anchor" href="#quan-ly-prompt" aria-label="Permalink to &quot;Quản lý Prompt&quot;">​</a></h1><blockquote><p>Kiểm soát hành vi cốt lõi của AI, thiết lập tư duy và tiêu chuẩn chấm điểm.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Prompt là những chỉ lệnh cốt lõi điều khiển toàn bộ nền tảng AI Coach. Tính năng này giúp quản trị viên điều chỉnh cách AI đóng vai khách hàng, tiêu chí đánh giá báo cáo, và các quy tắc hệ thống.</p><blockquote><p>Chỉ dành cho Quản trị viên.</p></blockquote><h2 id="cau-truc-giao-dien" tabindex="-1">Cấu trúc Giao diện <a class="header-anchor" href="#cau-truc-giao-dien" aria-label="Permalink to &quot;Cấu trúc Giao diện&quot;">​</a></h2><p>Trang quản lý được chia làm hai phần chính:</p><ul><li><strong>Thanh Công cụ &amp; Bộ lọc (Trái/Trên)</strong>: <ul><li><strong>Công ty/Phòng ban (Company/Department):</strong> Danh sách thả xuống để lọc bộ prompt áp dụng riêng cho một tổ chức (VD: 台灣國泰人壽).</li><li><strong>Phiên bản (Version):</strong> Chọn phiên bản prompt đang thao tác (VD: v1.0, v2.0 - Đang sử dụng).</li></ul></li><li><strong>Danh sách &amp; Trình soạn thảo</strong>: Khung hiển thị danh sách các Prompt và trình soạn thảo mã nguồn prompt chi tiết.</li></ul><hr><h2 id="chi-tiet-the-prompt" tabindex="-1">Chi tiết Thẻ Prompt <a class="header-anchor" href="#chi-tiet-the-prompt" aria-label="Permalink to &quot;Chi tiết Thẻ Prompt&quot;">​</a></h2><p>Mỗi thẻ prompt hiển thị:</p><ul><li><strong>Tên</strong>: Tên nhận dạng duy nhất trong hệ thống.</li><li><strong>Danh mục (Category)</strong>: Phân loại prompt (VD: System, Character, Judge, Auto-Suggestions).</li><li><strong>Mô tả</strong>: Tóm tắt ngắn gọn chức năng của nó.</li><li><strong>Trạng thái</strong>: Nhãn cho biết Prompt có đang nằm trong phiên bản &quot;Đang sử dụng/Active&quot; hay không.</li></ul><p>Trình soạn thảo cung cấp vùng không gian lớn để quản trị viên nhập văn bản Prompt một cách trực tiếp.</p><hr><h2 id="he-thong-bien-variables" tabindex="-1">Hệ thống Biến (Variables) <a class="header-anchor" href="#he-thong-bien-variables" aria-label="Permalink to &quot;Hệ thống Biến (Variables)&quot;">​</a></h2><p>Trong nội dung Prompt, bạn có thể sử dụng các biến động trong ngoặc nhọn <code>{...}</code> để hệ thống tự động điền dữ liệu thực tế tại thời điểm chạy: Ví dụ:</p><ul><li><code>{question}</code>: Câu hỏi mới nhất của người dùng.</li><li><code>{character_detail}</code>: Chân dung và tiểu sử khách hàng được tạo tự động.</li><li><code>{conversation_history}</code>: Lịch sử trò chuyện cho đến thời điểm hiện tại.</li><li><code>{stage_description}</code>: Mô tả của các giai đoạn bán hàng đang áp dụng.</li></ul><hr><h2 id="quan-ly-phien-ban-version-control" tabindex="-1">Quản lý Phiên bản (Version Control) <a class="header-anchor" href="#quan-ly-phien-ban-version-control" aria-label="Permalink to &quot;Quản lý Phiên bản (Version Control)&quot;">​</a></h2><p>Hệ thống cho phép bạn chỉnh sửa và kiểm thử Prompt mà không gây ảnh hưởng đến phiên bản người dùng đang sử dụng.</p><ul><li><strong>Thêm Phiên bản</strong>: Sao chép toàn bộ Prompt từ phiên bản hiện tại sang một phiên bản nháp mới.</li><li><strong>Lưu/Áp dụng sửa đổi</strong>: Các thay đổi chỉ tác động trong phạm vi phiên bản đã chọn.</li><li><strong>Phát hành (Publish)</strong>: Chính thức đưa phiên bản nháp lên môi trường thực tế làm phiên bản Đang sử dụng. Lưu ý: Phiên bản mới chỉ áp dụng cho các phiên luyện tập <em>mới</em> sau thời điểm phát hành.</li></ul>',21)])])}const m=t(a,[["render",r]]);export{u as __pageData,m as default};
